switch event {
        case .next: break
        case .error, .completed:
            self.this.dispose()
        }

        if self.parent.latest != self.id {
            return
        }

        switch event {
        case .next:
            self.parent.forwardOn(event)
        case .error:
            self.parent.forwardOn(event)
            self.parent.dispose()
        case .completed:
            self.parent.hasLatest = false
            if self.parent.stopped {
                self.parent.forwardOn(event)
                self.parent.dispose()
            }
        }

